import anthropic, json

# Lightweight hallucination probe — run as a synthetic monitor every 5 min
PROBE_QUESTIONS = [
    {
        "question": "What is the capital of France?",
        "expected_keyword": "Paris",
    },
    {
        "question": "What does HTTP stand for?",
        "expected_keyword": "HyperText Transfer Protocol",
    },
]

def run_hallucination_probe(model: str = "claude-haiku-4-5-20251001") -> dict:
    client = anthropic.Anthropic()
    results = []
    for probe in PROBE_QUESTIONS:
        response = client.messages.create(
            model=model,
            max_tokens=64,
            messages=[{"role": "user", "content": probe["question"]}],
        )
        answer = response.content[0].text
        passed = probe["expected_keyword"].lower() in answer.lower()
        results.append({"question": probe["question"], "passed": passed, "answer": answer})
    pass_rate = sum(r["passed"] for r in results) / len(results)
    return {"pass_rate": pass_rate, "results": results, "model": model}

# Call this from a Prometheus push gateway or write to a metrics endpoint
result = run_hallucination_probe()
print(json.dumps(result, indent=2))
# {"pass_rate": 1.0, "results": [...], "model": "claude-haiku-4-5-20251001"}

import re
from dataclasses import dataclass

# Patterns — extend these with domain-specific rules
PII_PATTERNS = [
    re.compile(r"\b\d{3}-\d{2}-\d{4}\b"),          # SSN
    re.compile(r"\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b"),  # email
    re.compile(r"\b(?:\d[ -]?){13,16}\b"),            # credit card-like
]
INJECTION_PATTERNS = [
    re.compile(r"ignore (previous|above|all) instructions", re.I),
    re.compile(r"you are now (a|an|the)", re.I),
    re.compile(r"(pretend|act as if) you (are|were|have no)", re.I),
]

@dataclass
class SafetyVerdict:
    safe: bool
    flags: list[str]

def check_response_safety(response_text: str, user_input: str) -> SafetyVerdict:
    flags = []
    for pattern in PII_PATTERNS:
        if pattern.search(response_text):
            flags.append(f"pii_detected:{pattern.pattern[:20]}")
    for pattern in INJECTION_PATTERNS:
        if pattern.search(user_input):
            flags.append(f"injection_attempt:{pattern.pattern[:20]}")
    return SafetyVerdict(safe=len(flags) == 0, flags=flags)

# In your request handler — runs synchronously before returning to user
verdict = check_response_safety(response_text="...", user_input="...")
if not verdict.safe:
    # 1. Block response from reaching user
    # 2. Push safety_incident_total counter to Prometheus
    # 3. Log full request/response to immutable audit store
    # 4. Fire PagerDuty SEV 1
    raise RuntimeError(f"Safety violation: {verdict.flags}")

import time, random

def llm_call_with_backoff(client, model: str, messages: list, *, max_retries: int = 5):
    """Exponential backoff with full jitter to avoid thundering-herd on 429."""
    for attempt in range(max_retries):
        try:
            return client.messages.create(model=model, max_tokens=512, messages=messages)
        except Exception as exc:
            if "429" not in str(exc) and "rate_limit" not in str(exc).lower():
                raise  # non-retryable
            if attempt == max_retries - 1:
                raise
            # Full jitter: random between 0 and cap (not additive)
            cap   = min(30, 2 ** attempt)          # seconds
            sleep = random.uniform(0, cap)
            time.sleep(sleep)
    raise RuntimeError("unreachable")
